import React, { useState } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import './App.css';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [mode, setMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setResults(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);

    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  return (
    <div className="app-container">
      {/* Header */}
      <div className="executive-header">
        <div className="header-content">
          <h1 className="header-title">Executive Churn Intelligence Platform</h1>
          <p className="header-subtitle">Unified predictive insights — action-first, financialized, and presentation-ready</p>
        </div>
      </div>

      {/* Model Status Banner */}
      <div className="model-status-banner">
        <div className="status-content">
          <strong>Model Status</strong>: Using <strong>simulated predictions and feature importances</strong> for demo. To enable real predictions: 
          1. Install required packages: <code>pip install xgboost catboost</code> 
          2. Place 'best_ensemble_churn_model.pkl' and 'feature_names.pkl' into the <code>Artifacts/</code> folder.
        </div>
      </div>

      <div className="main-dashboard">
        {/* Sidebar */}
        <div className="dashboard-sidebar">
          <div className="sidebar-section">
            <div className="sidebar-header">
              <h3>🎯 Analysis Mode</h3>
              <p>Choose your analysis approach</p>
            </div>

            <div className="mode-selection">
              <div 
                className={`mode-option ${mode === 'individual' ? 'active' : ''}`}
                onClick={() => setMode('individual')}
              >
                <span className="mode-icon">👤</span>
                <div className="mode-content">
                  <div className="mode-title">Individual Profile Analysis</div>
                </div>
              </div>

              <div 
                className={`mode-option ${mode === 'batch' ? 'active' : ''}`}
                onClick={() => setMode('batch')}
              >
                <span className="mode-icon">📊</span>
                <div className="mode-content">
                  <div className="mode-title">Batch File Upload</div>
                </div>
              </div>
            </div>
          </div>

          <div className="sidebar-section">
            <h4>⚡ Quick Actions</h4>
            <button className="quick-action-btn">
              📸 Export Dashboard PDF
            </button>
          </div>

          <div className="sidebar-section">
            <h4>ℹ️ Model Status</h4>
            <div className="status-indicator">
              <div className="status-dot demo"></div>
              <span>Using simulated predictions for demo</span>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="dashboard-content">
          {mode === 'individual' ? (
            <IndividualAnalysis 
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleIndividualAnalysis}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis 
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalysis}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </div>
    </div>
  );
}

// Individual Analysis Component
const IndividualAnalysis = ({ customerData, onInputChange, onAnalyze, loading, results }) => {
  const [activeTab, setActiveTab] = useState('core');

  const renderInputField = (label, field, type = 'number') => {
    return (
      <div className="input-field">
        <label className="input-label">{label}</label>
        <input 
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, parseFloat(e.target.value) || e.target.value)}
          className="input-control"
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      <div className="analysis-header">
        <h2>👤 Customer Profile Data Input</h2>
      </div>

      {/* Tabs */}
      <div className="analysis-tabs">
        <div className="tabs-navigation">
          <button 
            className={`tab-button ${activeTab === 'core' ? 'active' : ''}`}
            onClick={() => setActiveTab('core')}
          >
            💰 Core Metrics
          </button>
          <button 
            className={`tab-button ${activeTab === 'service' ? 'active' : ''}`}
            onClick={() => setActiveTab('service')}
          >
            🛠️ Service & Logistics
          </button>
          <button 
            className={`tab-button ${activeTab === 'demographic' ? 'active' : ''}`}
            onClick={() => setActiveTab('demographic')}
          >
            🧑‍ Demographic Data
          </button>
        </div>

        {/* Tab Content */}
        <div className="tab-content">
          {activeTab === 'core' && (
            <div className="input-grid">
              <div className="input-column">
                {renderInputField("1. Customer Lifetime (Months)", "Tenure")}
                {renderInputField("2. Total Orders", "OrderCount")}
                {renderInputField("3. Total Cashback Earned (₹)", "CashbackAmount")}
                {renderInputField("4. Days Since Last Order", "DaySinceLastOrder")}
              </div>
              <div className="input-column">
                {renderInputField("5. App Time (Hours/month)", "HourSpendOnApp")}
                {renderInputField("6. Perceived Price Increase (%)", "OrderAmountHikeFromlastYear")}
                {renderInputField("7. Coupons Used", "CouponUsed")}
                {renderInputField("8. Devices Registered", "NumberOfDeviceRegistered")}
              </div>
            </div>
          )}

          {activeTab === 'service' && (
            <div className="input-grid">
              <div className="input-column">
                {renderInputField("9. Satisfaction Score (1-5)", "SatisfactionScore")}
                {renderInputField("10. Warehouse Distance (km)", "WarehouseToHome")}
                {renderInputField("11. Delivery Addresses", "NumberOfAddress")}
                {renderInputField("12. City Tier", "CityTier")}
              </div>
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">13. Login Device</label>
                  <select 
                    value={customerData.PreferredLoginDevice} 
                    onChange={(e) => onInputChange("PreferredLoginDevice", e.target.value)}
                    className="input-control"
                  >
                    <option value="Mobile Phone">Mobile Phone</option>
                    <option value="Computer">Computer</option>
                  </select>
                </div>

                <div className="input-field">
                  <label className="input-label">14. Payment Mode</label>
                  <select 
                    value={customerData.PreferredPaymentMode} 
                    onChange={(e) => onInputChange("PreferredPaymentMode", e.target.value)}
                    className="input-control"
                  >
                    <option value="Credit Card">Credit Card</option>
                    <option value="Debit Card">Debit Card</option>
                    <option value="UPI">UPI</option>
                    <option value="E wallet">E wallet</option>
                    <option value="Cash on Delivery">Cash on Delivery</option>
                  </select>
                </div>

                <div className="input-field">
                  <label className="input-label">15. Order Category</label>
                  <select 
                    value={customerData.PreferedOrderCat} 
                    onChange={(e) => onInputChange("PreferedOrderCat", e.target.value)}
                    className="input-control"
                  >
                    <option value="Laptop & Accessory">Laptop & Accessory</option>
                    <option value="Mobile Phone">Mobile Phone</option>
                    <option value="Fashion">Fashion</option>
                    <option value="Grocery">Grocery</option>
                    <option value="Books & Stationery">Books & Stationery</option>
                    <option value="Footwear">Footwear</option>
                    <option value="Sports Equipment">Sports Equipment</option>
                    <option value="Others">Others</option>
                  </select>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'demographic' && (
            <div className="input-grid">
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">16. Gender</label>
                  <select 
                    value={customerData.Gender} 
                    onChange={(e) => onInputChange("Gender", e.target.value)}
                    className="input-control"
                  >
                    <option value="Male">Male</option>
                    <option value="Female">Female</option>
                    <option value="Other">Other</option>
                  </select>
                </div>

                <div className="input-field">
                  <label className="input-label">17. Marital Status</label>
                  <select 
                    value={customerData.MaritalStatus} 
                    onChange={(e) => onInputChange("MaritalStatus", e.target.value)}
                    className="input-control"
                  >
                    <option value="Married">Married</option>
                    <option value="Single">Single</option>
                    <option value="Divorced">Divorced</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
              </div>
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">18. Has Formal Complaint?</label>
                  <div className="toggle-group">
                    <button 
                      className={`toggle-btn ${customerData.Complain ? 'active' : ''}`}
                      onClick={() => onInputChange("Complain", 1)}
                    >
                      Yes
                    </button>
                    <button 
                      className={`toggle-btn ${!customerData.Complain ? 'active' : ''}`}
                      onClick={() => onInputChange("Complain", 0)}
                    >
                      No
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <button 
        className="analyze-button primary"
        onClick={onAnalyze}
        disabled={loading}
      >
        {loading ? '🔄 Analyzing...' : '✨ Analyze Customer Risk Now'}
      </button>

      {/* Results Display */}
      {results && (
        <div className="results-section">
          <h3>Analysis Results</h3>
          <div className="risk-indicator">
            <div className={`risk-badge ${results.risk_level.toLowerCase()}`}>
              {results.risk_level} RISK ({(results.probability * 100).toFixed(1)}%)
            </div>
            <p>Primary risk factor: <strong>{results.top_driver}</strong></p>
          </div>
        </div>
      )}
    </div>
  );
};

// Batch Analysis Component
const BatchAnalysis = ({ onFileChange, onAnalyze, loading, results }) => {
  return (
    <div className="batch-analysis">
      <div className="analysis-header">
        <h2>📊 Batch Customer Analysis</h2>
        <p>Upload a CSV file containing multiple customer profiles for batch analysis</p>
      </div>

      <div className="upload-section">
        <div className="file-upload-area">
          <input 
            type="file" 
            accept=".csv"
            onChange={onFileChange}
            className="file-input"
          />
          <div className="upload-placeholder">
            <div className="upload-icon">📁</div>
            <p>Click to upload CSV file or drag and drop</p>
            <small>Supports .csv files with customer data</small>
          </div>
        </div>

        <button 
          className="analyze-button primary"
          onClick={onAnalyze}
          disabled={loading}
        >
          {loading ? '🔄 Processing...' : '📊 Analyze Batch Data'}
        </button>
      </div>

      {results && (
        <div className="batch-results">
          <h3>Batch Analysis Complete</h3>
          <div className="results-summary">
            <div className="summary-item">
              <span className="summary-value">{results.summary?.total_customers || 0}</span>
              <span className="summary-label">Total Customers</span>
            </div>
            <div className="summary-item">
              <span className="summary-value">{results.summary?.high_risk_percentage?.toFixed(1) || 0}%</span>
              <span className="summary-label">High Risk</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
